import{_ as t,c as i,o as r,a1 as s}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Extending Superpowers: Skills, Testing & Contributing | Superpowers Tutorial","description":"Learn how to write custom skills, test them, and contribute to the Superpowers project. Master skill development to customize your own AI coding workflow.","frontmatter":{"title":"Extending Superpowers: Skills, Testing & Contributing | Superpowers Tutorial","sidebarTitle":"Extending","subtitle":"Extending Superpowers","description":"Learn how to write custom skills, test them, and contribute to the Superpowers project. Master skill development to customize your own AI coding workflow.","order":210},"headers":[],"relativePath":"obra/superpowers/extending/index.md","filePath":"obra/superpowers/extending/index.md"}'),o={name:"obra/superpowers/extending/index.md"};function a(n,e,l,u,d,p){return r(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="extending-superpowers" tabindex="-1">Extending Superpowers <a class="header-anchor" href="#extending-superpowers" aria-label="Permalink to &quot;Extending Superpowers&quot;">​</a></h1><p>This chapter teaches you how to extend Superpowers: writing custom skills, testing skills, and contributing to the project. After completing this chapter, you can build your own AI coding workflow and share your results with the community.</p><h2 id="subpage-navigation" tabindex="-1">Subpage Navigation <a class="header-anchor" href="#subpage-navigation" aria-label="Permalink to &quot;Subpage Navigation&quot;">​</a></h2><h3 id="writing-custom-skills" tabindex="-1"><a href="./../writing-skills/">Writing Custom Skills</a> <a class="header-anchor" href="#writing-custom-skills" aria-label="Permalink to &quot;[Writing Custom Skills](../writing-skills/)&quot;">​</a></h3><p>Learn to write your own skills following best practices. Master every step of skill development, from skill structure and metadata definition to actual implementation.</p><h3 id="testing-skills" tabindex="-1"><a href="./../testing-skills/">Testing Skills</a> <a class="header-anchor" href="#testing-skills" aria-label="Permalink to &quot;[Testing Skills](../testing-skills/)&quot;">​</a></h3><p>Use sub-agents to test your custom-written skills, ensuring they work correctly in various scenarios. Learn how to write test cases and validation methods.</p><h3 id="contributing-guide" tabindex="-1"><a href="./../contributing/">Contributing Guide</a> <a class="header-anchor" href="#contributing-guide" aria-label="Permalink to &quot;[Contributing Guide](../contributing/)&quot;">​</a></h3><p>Contribute skills and improvements to the Superpowers project. Understand the contribution process, code standards, and submission workflow to benefit more people from your work.</p><h2 id="recommended-learning-path" tabindex="-1">Recommended Learning Path <a class="header-anchor" href="#recommended-learning-path" aria-label="Permalink to &quot;Recommended Learning Path&quot;">​</a></h2><p>We recommend learning the content in this chapter in the following order:</p><ol><li><strong>Writing Custom Skills</strong>: First master the basic structure and development standards of skills</li><li><strong>Testing Skills</strong>: Ensure the quality of the skills you write is reliable</li><li><strong>Contributing Guide</strong>: Share excellent skills with the community</li></ol><div class="tip custom-block"><p class="custom-block-title">Tip</p><p>Before learning to write skills, we recommend completing <a href="./../../start/using-skills/">How to Use Skills</a> and at least 2-3 core workflows first. This will help you better understand the application scenarios of skills.</p></div><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before starting this chapter, ensure:</p><ul><li>✅ Completed <a href="./../../start/quick-start/">Quick Start</a></li><li>✅ Familiar with at least 2 core workflows (e.g., <a href="./../../core-workflows/design-workflow/">Design Workflow</a> and <a href="./../../core-workflows/tdd-workflow/">TDD Workflow</a>)</li><li>✅ Understand basic Markdown writing standards</li><li>✅ Have some programming experience (JavaScript/TypeScript preferred)</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>After completing this chapter, you can:</p><ul><li>Check <a href="./../../faq/troubleshooting/">FAQ &amp; Troubleshooting</a> to solve issues you encounter</li><li>Read <a href="./../../faq/best-practices/">Best Practices &amp; Pitfalls Guide</a> to learn in-depth usage techniques</li><li>Reference <a href="./../../appendix/skills-reference/">Skills Complete Reference</a> to see all available skills</li></ul>',19)])])}const g=t(o,[["render",a]]);export{h as __pageData,g as default};
